using System.Collections;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Switch/Botão genérico (Etapa 6.1). Activável por toque (player e,
/// opcionalmente, inimigos — EnemyWeaknessConfig.canActivateButton, Etapa 6.2)
/// e por projécteis (IProjectileActivatable — projécteis com
/// "canActivateSwitches", Etapa 2.2; "atirar" no switch).
///
/// Modo "momentary" = botão: desactiva-se sozinho após "resetDelay" (a
/// variável global volta ao valor inactivo). Sem "momentary" = switch fixo.
/// Escreve numa variável global (GameVariables), como o Lever.
///
/// Persistência: se <see cref="persistState"/> estiver activo, ao reentrar na
/// cena o switch restaura o estado a partir de <see cref="variableName"/> —
/// puzzle "permanente". Se desactivo (padrão), volta ao Inspector → reinicia.
/// Nota: "momentary" e "persistState" em conjunto fazem pouco sentido — o
/// botão momentâneo pressupõe que o estado retorna a "inactivo" sozinho.
/// </summary>
public class Switch : MonoBehaviour, IProjectileActivatable
{
    [Header("Estado")]
    public bool isActive = false;

    [Header("Variável Global (GameVariables)")]
    [Tooltip("Nome da variável global escrita com o estado. Vazio = não escreve.")]
    public string variableName = "";

    [Tooltip("Se activo, escreve a variável como INT (1/0) em vez de BOOL.")]
    public bool writeAsInt = false;

    [Header("Persistência após Morte / Saída de Área")]
    [Tooltip("GDD: 'Puzzles concluídos permanecem resolvidos quando configurados como persistentes.'\n\nLigado → ao reentrar na cena, restaura 'isActive' a partir de 'variableName' (GameVariables).\nDesligado (padrão) → escreve o padrão Inspector → puzzle reinicia.\n\nNão combinar com 'momentary' (botão momentâneo pressupõe reset automático).")]
    public bool persistState = false;

    [Header("Activação")]
    [Tooltip("Toque do player (trigger) activa.")]
    public bool activateOnPlayerTouch = true;

    [Tooltip("Toque de um inimigo com 'canActivateButton' (EnemyData.weaknesses) activa (Etapa 6.2).")]
    public bool activateOnEnemyTouch = false;

    [Tooltip("Projécteis com 'canActivateSwitches' (ProjectileData) activam — 'atirar no alvo'.")]
    public bool activateOnProjectile = true;

    [Tooltip("Só pode ser activado uma vez.")]
    public bool oneShot = false;

    [Header("Botão (Momentâneo)")]
    [Tooltip("Se activo, comporta-se como botão: desactiva-se sozinho após 'resetDelay' segundos.")]
    public bool momentary = false;

    [Min(0f)] public float resetDelay = 1f;

    [Header("Visual (opcional)")]
    public SpriteRenderer spriteRenderer;
    public Sprite spriteActive;
    public Sprite spriteInactive;

    [Header("Eventos")]
    public UnityEvent<bool> onChanged;

    private bool _used;
    private Coroutine _resetRoutine;

    private void Start()
    {
        if (persistState && !string.IsNullOrEmpty(variableName) && GameVariables.Instance != null)
        {
            bool saved = writeAsInt
                ? GameVariables.Instance.GetInt(variableName) != 0
                : GameVariables.Instance.GetBool(variableName);
            isActive = saved;
            ApplyVisual();
        }
        else
        {
            Apply();
        }
    }

    /// <summary>Activa o switch (ponto de entrada genérico — também chamável por NpcAction/puzzles).</summary>
    public void Activate()
    {
        if (isActive || (oneShot && _used)) return;

        isActive = true;
        _used = true;
        Apply();
        onChanged?.Invoke(true);

        if (momentary)
        {
            if (_resetRoutine != null) StopCoroutine(_resetRoutine);
            _resetRoutine = StartCoroutine(ResetRoutine());
        }
    }

    /// <summary>Desactiva o switch (automático no modo "momentary"; manual para puzzles que fazem reset).</summary>
    public void Deactivate()
    {
        if (!isActive) return;

        isActive = false;
        Apply();
        onChanged?.Invoke(false);
    }

    private IEnumerator ResetRoutine()
    {
        yield return new WaitForSeconds(resetDelay);
        Deactivate();
        _resetRoutine = null;
    }

    private void Apply()
    {
        if (!string.IsNullOrEmpty(variableName) && GameVariables.Instance != null)
        {
            if (writeAsInt) GameVariables.Instance.SetInt(variableName, isActive ? 1 : 0);
            else GameVariables.Instance.SetBool(variableName, isActive);
        }

        ApplyVisual();
    }

    private void ApplyVisual()
    {
        if (spriteRenderer != null)
        {
            var sprite = isActive ? spriteActive : spriteInactive;
            if (sprite != null) spriteRenderer.sprite = sprite;
        }
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (activateOnPlayerTouch && other.CompareTag("Player"))
        {
            Activate();
            return;
        }

        if (activateOnEnemyTouch)
        {
            var enemy = other.GetComponent<EnemyController>();
            if (enemy != null && enemy.Data != null && enemy.Data.weaknesses.canActivateButton && !enemy.IsTerminal)
                Activate();
        }
    }

    /// <summary>Activação por projéctil (IProjectileActivatable — ProjectileController, Etapa 2.2).</summary>
    public void ActivateByProjectile(ProjectileController projectile)
    {
        if (activateOnProjectile) Activate();
    }
}
